import React, { useState, useEffect, useCallback } from "react";
import Fade from "@mui/material/Fade";
import { Card } from "@mui/material";
import { Size } from "media-query";
import {
  cardbgcolor,
  textcolor,
  pagetitlecolor,
  cardtitlecolor,
  pagebgcolor,
  fontType,
} from "components/Display/feutures";

const topPageMax = 100;

const SolutionContext = () => {
  return (
    <div>
      <Card className="bg-gray-light">
        At CloudCraft, we specialize in delivering innovative web development
        solutions tailored to meet your unique business needs. Our expertise
        spans a robust technology stack, including JavaScript, TypeScript,
        Node.js, and Angular for dynamic front-end experiences, complemented by
        Python3 and PostgreSQL for powerful back-end functionality. We harness
        the versatility of Tailwind, Material UI, and PrimeNG to create visually
        stunning and user-friendly interfaces. Our commitment to best practices
        in version control with GIT ensures seamless collaboration and code
        management. Leveraging AWS services such as EC2, ECS, EKS, and Lambda,
        we build scalable and resilient applications that are optimized for
        performance and reliability. With a focus on cloud infrastructure, we
        utilize tools like Elastic Load Balancing, CloudWatch, EventBridge, Auto
        Scaling, and VPC to enhance operational efficiency and deliver
        exceptional value to our clients. Partner with us to elevate your
        digital presence and drive your business forward.
      </Card>
    </div>
  );
};

export const Solutions = () => {
  const [y, setY] = useState(window.scrollY);

  useEffect(() => {
    const handleScroll = () => setY(window.scrollY);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    window.scrollTo({ top: 0, left: 0, behavior: "smooth" });
  }, []);

  return (
    <div className="block h-auto">
      <Fade in={y < topPageMax} timeout={1000}>
        <h1
          style={{ color: pagetitlecolor, fontFamily: fontType }}
          className="text-center font-bold text-3xl mt-16 pt-2"
        >
          Solutions
        </h1>
      </Fade>
      <Fade in={y < topPageMax} timeout={1500}>
        <div className="flex text-center justify-center p-2">
          <SolutionContext />
        </div>
      </Fade>
    </div>
  );
};
